import java.util.Objects;

public class Propietario {
    private String dni;
    private String nombre;
    private String telefono;

    // Constructor normal: recibe los 3 datos y los guarda
    public Propietario(String dni, String nombre, String telefono) {
        this.dni = dni;
        this.nombre = nombre;
        setTelefono(telefono); // usamos el setter para validar ya desde aquí
    }

    // Constructor de copia: recibe OTRO Propietario y copia sus datos
    // Así p2 = new Propietario(p1) crea un objeto NUEVO independiente de p1
    public Propietario(Propietario otro) {
        this.dni = otro.dni;
        this.nombre = otro.nombre;
        this.telefono = otro.telefono;
    }

    // Getters: permiten leer los datos desde fuera de la clase
    public String getDni()      { return dni; }
    public String getNombre()   { return nombre; }
    public String getTelefono() { return telefono; }

    // Setters normales para dni y nombre
    public void setDni(String dni)       { this.dni = dni; }
    public void setNombre(String nombre) { this.nombre = nombre; }

    // Setter con validación: solo guarda si tiene exactamente 9 caracteres
    public void setTelefono(String telefono) {
        if (telefono != null && telefono.length() == 9) {
            this.telefono = telefono;
        }
        // Si no cumple la condición, no hace nada — el valor no cambia
    }

    // equals: dos Propietario son iguales si tienen el mismo DNI
    // Objects.equals evita NullPointerException si dni fuera null
    @Override
    public boolean equals(Object o) {
        if (this == o) return true; // es el mismo objeto en memoria
        if (o == null || getClass() != o.getClass()) return false;
        Propietario that = (Propietario) o;
        return Objects.equals(dni, that.dni);
    }

    // hashCode debe basarse en los mismos campos que equals
    @Override
    public int hashCode() {
        return Objects.hash(dni);
    }

    // toString: lo que se muestra al hacer System.out.println(propietario)
    @Override
    public String toString() {
        return "Propietario[dni=" + dni + ", nombre=" + nombre + ", telefono=" + telefono + "]";
    }
}

public interface Informable {
    // Solo la firma del método, sin cuerpo ({}).
    // Cualquier clase que ponga 'implements Informable'
    // DEBE tener este método o el compilador dará error.
    String generarInforme();
}

public class Mascota implements Informable {
    private String nombre;
    private String especie;
    private int edad;
    private Propietario propietario;

    // static: existe UNA sola vez para toda la clase
    // No está dentro de ningún objeto, es de la clase Mascota
    private static int totalMascotas = 0;

    public Mascota(String nombre, String especie, int edad, Propietario propietario) {
        this.nombre = nombre;
        this.especie = especie;
        setEdad(edad);           // usamos el setter para que valide
        this.propietario = propietario;
        totalMascotas++;         // cada new Mascota() sube el contador
    }

    // Getters
    public String getNombre()           { return nombre; }
    public String getEspecie()          { return especie; }
    public int getEdad()                { return edad; }
    public Propietario getPropietario() { return propietario; }

    // Setters
    public void setNombre(String nombre)      { this.nombre = nombre; }
    public void setEspecie(String especie)    { this.especie = especie; }
    public void setPropietario(Propietario p) { this.propietario = p; }

    // Setter con validación: edad negativa no tiene sentido
    public void setEdad(int edad) {
        if (edad >= 0) {
            this.edad = edad;
        }
        // Si es negativa, no hace nada — el valor anterior se mantiene
    }

    // Devuelve true si tiene menos de 2 años, false si tiene 2 o más
    public boolean esCachorro() {
        return this.edad < 2;
    }

    // Método estático: se llama como Mascota.getTotalMascotas()
    public static int getTotalMascotas() {
        return totalMascotas;
    }

    @Override
    public String toString() {
        // OJO: propietario.getNombre() — NO propietario.toString()
        // Si usáramos toString() saldría: Propietario[dni=..., nombre=Ana, telefono=...]
        // El formato pedido solo quiere el nombre
        return "Mascota[nombre=" + nombre + ", especie=" + especie + ", edad=" + edad +
               ", propietario=" + propietario.getNombre() + "]";
    }

    // Viene de implements Informable — obligatorio implementarlo
    @Override
    public String generarInforme() {
        String estado = esCachorro() ? "Cachorro" : "Adulto"; // operador ternario: condición ? siTrue : siFalse
        return "Mascota: " + nombre + " (" + especie + ") - " + estado +
               " | Propietario: " + propietario.getNombre();
    }
}

