public abstract class Empleado {
    // protected: las subclases pueden acceder directamente
    // Si fueran private, Veterinario no podría usar this.nombre
    protected String nombre;
    protected double salarioBase;

    public Empleado(String nombre, double salarioBase) {
        this.nombre = nombre;
        this.salarioBase = salarioBase;
    }

    // abstract: no tiene cuerpo aquí — obliga a las subclases a implementarlo
    // Cada subclase calcula el salario de forma diferente
    abstract double calcularSalario();

    @Override
    public String toString() {
        // %.2f formatea el double con 2 decimales: 1500.0 → 1500,00
        return String.format("[Empleado] %s | Salario: %.2f EUR", nombre, calcularSalario());
    }
}


