public class Veterinario extends Empleado implements Informable, Comparable<Veterinario> {
    // 'extends Empleado' = hereda nombre, salarioBase y el toString del padre
    // 'implements Informable' = obligado a tener generarInforme()
    // 'implements Comparable<Veterinario>' = obligado a tener compareTo()
    private String especialidad;

    public Veterinario(String nombre, double salarioBase, String especialidad) {
        super(nombre, salarioBase); // OBLIGATORIO: llama al constructor de Empleado
        this.especialidad = especialidad;
    }

    // Su salario es el base + 500 euros fijos de complemento
    @Override
    double calcularSalario() {
        return salarioBase + 500.0;
    }

    @Override
    public String toString() {
        return String.format("[Veterinario] %s (%s) | Salario: %.2f EUR",
                             nombre, especialidad, calcularSalario());
    }

    // Viene de implements Informable
    @Override
    public String generarInforme() {
        return "Veterinario: " + nombre + " | Especialidad: " + especialidad +
               String.format(" | Salario: %.2f", calcularSalario());
    }

    // Viene de implements Comparable<Veterinario>
    // compareTo: negativo si this < otro, 0 si iguales, positivo si this > otro
    // Aquí comparamos por salario calculado
    @Override
    public int compareTo(Veterinario otro) {
        return Double.compare(this.calcularSalario(), otro.calcularSalario());
    }
}


