public class Auxiliar extends Empleado {
    private String turno; // valores posibles: "mañana", "tarde", "noche"

    public Auxiliar(String nombre, double salarioBase, String turno) {
        super(nombre, salarioBase); // OBLIGATORIO
        this.turno = turno;
    }

    // Si trabaja de noche cobra un 20% más
    // equalsIgnoreCase: compara ignorando mayúsculas/minúsculas
    @Override
    double calcularSalario() {
        if ("noche".equalsIgnoreCase(turno)) {
            return salarioBase * 1.20;
        }
        return salarioBase;
    }

    @Override
    public String toString() {
        return String.format("[Auxiliar] %s (%s) | Salario: %.2f EUR",
                             nombre, turno, calcularSalario());
    }
}

import java.util.ArrayList;

// La <T> es el tipo genérico — un comodín que defines al crear el objeto:
// new Repositorio<Mascota>()  →  T se convierte en Mascota
// new Repositorio<String>()   →  T se convierte en String
public class Repositorio<T> {
    private ArrayList<T> elementos;

    public Repositorio() {
        this.elementos = new ArrayList<>();
    }

    // Añadir un elemento al final de la lista
    public void agregar(T elemento) {
        elementos.add(elemento);
    }

    // Eliminar si existe. remove() usa equals() para buscarlo.
    // Devuelve true si lo encontró y eliminó, false si no estaba
    public boolean eliminar(T elemento) {
        return elementos.remove(elemento);
    }

    // Obtener elemento por posición
    // Si el índice no existe devuelve null (en vez de lanzar excepción)
    public T buscarPorIndice(int i) {
        if (i >= 0 && i < elementos.size()) {
            return elementos.get(i);
        }
        return null;
    }

    // Cuántos elementos hay en este momento
    public int totalElementos() {
        return elementos.size();
    }

    // Mostrar todos. Como T puede ser cualquier clase,
    // usamos toString() que todos los objetos Java tienen
    public void mostrarTodos() {
        for (T elemento : elementos) {
            System.out.println(elemento.toString());
        }
    }
}

import java.util.HashMap;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;

public class GestorClinica {
    // HashMap: busca mascota por nombre al instante (clave → valor)
    private Map<String, Mascota> mascotas;
    // HashSet: guarda solo especies únicas, rechaza duplicados
    private Set<String> especies;

    public GestorClinica() {
        this.mascotas = new HashMap<>();
        this.especies = new HashSet<>();
    }

    public void registrarMascota(Mascota m) {
        mascotas.put(m.getNombre(), m);  // clave = nombre, valor = objeto Mascota
        especies.add(m.getEspecie());    // si ya existe 'Perro', el Set lo ignora
    }

    // get() devuelve null automáticamente si la clave no existe
    public Mascota buscarPorNombre(String nombre) {
        return mascotas.get(nombre);
    }

    public void mostrarEspecies() {
        System.out.println("Especies registradas:");
        for (String especie : especies) {
            System.out.println("- " + especie);
        }
    }

    // entrySet() devuelve todas las entradas del mapa como pares clave/valor
    public void mostrarTodasLasMascotas() {
        System.out.println("Mascotas en el sistema:");
        for (Map.Entry<String, Mascota> entry : mascotas.entrySet()) {
            System.out.println(entry.getKey() + " -> " + entry.getValue().toString());
        }
    }
}

// Método genérico estático — va dentro de la clase Main, ANTES del public static void main
//
// Desglose de la firma: public static <T extends Comparable<T>> void mostrarMayor(T a, T b)
//   public         → accesible desde cualquier clase
//   static         → es de la clase, no de un objeto. Se llama como mostrarMayor(...) directamente
//   <T extends Comparable<T>> → T es el tipo genérico con restricción:
//                                T puede ser cualquier tipo SIEMPRE QUE implemente Comparable<T>
//                                String, Integer, Veterinario (los 3 lo implementan)
//   void           → no devuelve ningún valor
//   T a, T b       → dos parámetros del mismo tipo T
public static <T extends Comparable<T>> void mostrarMayor(T a, T b) {
    // compareTo devuelve:
    //   número positivo  si a > b
    //   0                si a == b
    //   número negativo  si a < b
    int resultado = a.compareTo(b);
    if (resultado > 0) {
        System.out.println("El mayor es: " + a);
    } else if (resultado < 0) {
        System.out.println("El mayor es: " + b);
    } else {
        System.out.println("Ambos son iguales.");
    }
}

