    .filter(m -> m.getEspecie().equals("Perro"))        // solo los de especie Perro
    .sorted(Comparator.comparing(Mascota::getNombre))   // ordenados por nombre
    .forEach(System.out::println);                       // mostrar cada uno

// h) Edad media: map extrae la edad, reduce suma todas
